// Build the Empire-style goal poster as HTML
const data = $input.first().json.body || $input.first().json;

const name = data.name || 'مواطن الإمبراطورية';
const goal = data.goal || '';
const why = data.why || '';
const future = data.future || '';
const commitment = data.commitment || '';
const habit = data.habit || '';
const message = data.message || '';
const scale = data.commitment_scale || '?';
const telegram_id = data.telegram_id || '';
const telegram_username = data.telegram_username || '';

// Date in Arabic
const now = new Date();
const dateStr = now.toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' });

const html = `
<html>
<head>
<meta charset="UTF-8">
<style>
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&family=Cinzel:wght@600;700;900&display=swap');

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  width: 1080px;
  height: 1920px;
  background: #0A0A0F;
  font-family: 'Cairo', sans-serif;
  direction: rtl;
  position: relative;
  overflow: hidden;
}

/* Background effects */
body::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse at 30% 20%, rgba(212,175,55,0.06) 0%, transparent 50%),
    radial-gradient(ellipse at 70% 80%, rgba(212,175,55,0.04) 0%, transparent 50%);
}

/* Gold border frame */
.frame {
  position: absolute;
  inset: 30px;
  border: 2px solid rgba(212,175,55,0.4);
  border-radius: 20px;
}
.frame::after {
  content: '';
  position: absolute;
  inset: 8px;
  border: 1px solid rgba(212,175,55,0.15);
  border-radius: 16px;
}

.content {
  position: relative;
  z-index: 1;
  padding: 80px 60px;
  height: 100%;
  display: flex;
  flex-direction: column;
}

/* Header */
.header {
  text-align: center;
  margin-bottom: 40px;
}
.crown { font-size: 56px; margin-bottom: 12px; }
.brand {
  font-family: 'Cinzel', serif;
  font-size: 18px;
  letter-spacing: 4px;
  color: rgba(212,175,55,0.6);
  margin-bottom: 16px;
}
.title {
  font-size: 42px;
  font-weight: 900;
  background: linear-gradient(135deg, #D4AF37, #e8d48b, #D4AF37);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 8px;
}
.subtitle {
  font-size: 20px;
  color: #8B919A;
}
.name-badge {
  display: inline-block;
  margin-top: 16px;
  padding: 8px 32px;
  border: 1.5px solid rgba(212,175,55,0.4);
  border-radius: 30px;
  color: #D4AF37;
  font-size: 24px;
  font-weight: 700;
  background: rgba(212,175,55,0.05);
}

/* Divider */
.divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(212,175,55,0.4), transparent);
  margin: 30px 0;
}

/* Goal sections */
.section {
  margin-bottom: 28px;
}
.section-icon {
  font-size: 22px;
  margin-left: 8px;
}
.section-label {
  font-size: 14px;
  font-weight: 600;
  color: rgba(212,175,55,0.7);
  letter-spacing: 1px;
  margin-bottom: 8px;
  text-transform: uppercase;
  font-family: 'Cinzel', serif;
}
.section-text {
  font-size: 22px;
  font-weight: 600;
  color: #F5F0E8;
  line-height: 1.7;
  padding: 16px 20px;
  background: rgba(17,17,24,0.8);
  border: 1px solid rgba(212,175,55,0.1);
  border-radius: 12px;
  border-right: 3px solid #D4AF37;
}

/* Scale badge */
.scale-badge {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  padding: 12px 24px;
  background: rgba(212,175,55,0.08);
  border: 1.5px solid rgba(212,175,55,0.3);
  border-radius: 12px;
  margin-bottom: 28px;
}
.scale-num {
  font-size: 36px;
  font-weight: 900;
  color: #D4AF37;
}
.scale-label {
  font-size: 16px;
  color: #8B919A;
}

/* Habit card */
.habit-card {
  background: rgba(212,175,55,0.05);
  border: 1.5px solid rgba(212,175,55,0.2);
  border-radius: 14px;
  padding: 20px 24px;
  text-align: center;
  margin-bottom: 28px;
}
.habit-text {
  font-size: 22px;
  font-weight: 700;
  color: #D4AF37;
  line-height: 1.6;
}

/* Message */
.message-box {
  background: rgba(13,17,23,0.8);
  border: 1px solid rgba(212,175,55,0.15);
  border-radius: 12px;
  padding: 20px;
  text-align: center;
  margin-top: auto;
}
.message-text {
  font-size: 20px;
  font-style: italic;
  color: #e8d48b;
  line-height: 1.6;
}
.message-label {
  font-size: 13px;
  color: #8B919A;
  margin-top: 8px;
}

/* Footer */
.footer {
  text-align: center;
  margin-top: 30px;
  padding-top: 20px;
  border-top: 1px solid rgba(212,175,55,0.1);
}
.footer-text {
  font-family: 'Cinzel', serif;
  font-size: 13px;
  color: rgba(212,175,55,0.4);
  letter-spacing: 3px;
}
.footer-date {
  font-size: 13px;
  color: #8B919A;
  margin-top: 6px;
}
</style>
</head>
<body>
<div class="frame"></div>
<div class="content">

  <div class="header">
    <div class="crown">👑</div>
    <div class="brand">EMPIRE ENGLISH COMMUNITY</div>
    <div class="title">ميثاق الأهداف</div>
    <div class="subtitle">Goal Covenant</div>
    <div class="name-badge">${name}</div>
  </div>

  <div class="divider"></div>

  <div class="section">
    <div class="section-label"><span class="section-icon">🎯</span> هدفي</div>
    <div class="section-text">${goal}</div>
  </div>

  <div class="section">
    <div class="section-label"><span class="section-icon">💡</span> ليه مهم</div>
    <div class="section-text">${why}</div>
  </div>

  <div class="scale-badge">
    <div class="scale-num">${scale}/10</div>
    <div class="scale-label">مستوى الجدية</div>
  </div>

  <div class="section">
    <div class="section-label"><span class="section-icon">✊</span> التزامي</div>
    <div class="section-text">${commitment}</div>
  </div>

  <div class="habit-card">
    <div class="section-label" style="margin-bottom:12px"><span class="section-icon">☀️</span> عادتي اليومية</div>
    <div class="habit-text">${habit}</div>
  </div>

  ${message ? `
  <div class="message-box">
    <div class="message-text">"${message}"</div>
    <div class="message-label">💌 رسالة لنفسي في المستقبل</div>
  </div>
  ` : ''}

  <div class="footer">
    <div class="footer-text">EMPIRE ENGLISH COMMUNITY</div>
    <div class="footer-date">${dateStr}</div>
  </div>

</div>
</body>
</html>
`;

return [{
  json: {
    html: html,
    telegram_id: telegram_id,
    telegram_username: telegram_username,
    name: name
  }
}];

// Prepare Telegram sendPhoto — image comes as binary from html2img
const prevData = $('Generate Poster HTML').first().json;
const chatId = prevData.telegram_id;
const name = prevData.name;

if (!chatId) {
  return [{ json: { skip: true, reason: 'no_telegram_id' } }];
}

return [{
  json: {
    chat_id: chatId,
    caption: `👑 ميثاق أهدافك جاهز يا ${name}!\n\nعلّق البوستر ده في مكان تشوفه كل يوم — خلّيه تذكير دائم بالتزامك.\n\n🏛 Empire English Community`,
    name: name
  },
  binary: $input.first().binary
}];
